Rule.Source:
import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

import sailpoint.object.ObjectAttribute;
import sailpoint.object.ObjectConfig;
import sailpoint.object.RoleTypeDefinition;
import sailpoint.tools.Util;

String roleTypeArg = roleType != null ? roleType.toString().trim().toLowerCase() : "it";
boolean isItRole = "it".equals(roleTypeArg);
boolean isBusinessRole = "business".equals(roleTypeArg);
if (!isItRole && !isBusinessRole) {
  throw new IllegalArgumentException("roleType must be 'it' or 'business'");
}

ObjectConfig objConfig = context.getObjectByName(ObjectConfig.class, "Bundle");
RoleTypeDefinition roleDef = objConfig.getRoleType(isItRole ? "it" : "business");
List disAllowedAttributes = roleDef.getDisallowedAttributes();
List objectAttributes = objConfig.getObjectAttributes();

List roleHeader = new ArrayList();
roleHeader.add("Role Name");
roleHeader.add("DisplayName");
roleHeader.add("Type");
roleHeader.add("Owner");
roleHeader.add("Description");
roleHeader.add("Disabled");

for (ObjectAttribute objAttr : Util.safeIterable(objectAttributes)) {
  if (!Util.nullSafeContains(disAllowedAttributes, objAttr.getName())) {
    roleHeader.add(objAttr.getName());
  }
}

if (isItRole) {
  roleHeader.add("AddEntitlement");
  roleHeader.add("RemoveEntitlement");
} else {
  roleHeader.add("AddITRoles");
  roleHeader.add("RemoveITRoles");
}

Map columnValidations = new HashMap();

List typeValues = new ArrayList();
typeValues.add(isItRole ? "it" : "business");
columnValidations.put("Type", typeValues);

List disabledValues = new ArrayList();
disabledValues.add("TRUE");
disabledValues.add("FALSE");
columnValidations.put("Disabled", disabledValues);

for (ObjectAttribute objAttr : Util.safeIterable(objectAttributes)) {
  if (!Util.nullSafeContains(disAllowedAttributes, objAttr.getName())) {
    List allowedList = new ArrayList();
    if ("boolean".equals(objAttr.getType())) {
      allowedList.add("TRUE");
      allowedList.add("FALSE");
    } else {
      List allowedValues = objAttr.getAllowedValues();
      if (allowedValues != null && !allowedValues.isEmpty()) {
        for (Object valueObj : allowedValues) {
          if (valueObj != null) {
            String value = String.valueOf(valueObj).trim();
            if (value.length() > 0) {
              allowedList.add(value);
            }
          }
        }
      }
    }
    if (!allowedList.isEmpty()) {
      columnValidations.put(objAttr.getName(), allowedList);
    }
  }
}

Map result = new HashMap();
result.put("roleHeader", roleHeader);
result.put("columnValidations", columnValidations);
result.put("rolesSheetName", isItRole ? "IT Roles" : "Business Roles");
result.put("roleType", roleTypeArg);

return result;
